import type { AdapterCapabilities, AdapterCategory, HealthMetrics } from '../../types/adapter';
import type { NormalizedProtocolMetrics, NormalizedYieldPool } from '../../types/defi';
import { RateLimiter } from '../../rate-limiter/rate-limiter';
import type {
  DefiLlamaRawProtocol,
  DefiLlamaRawProtocolDetail,
  DefiLlamaRawYieldPool,
  DefiLlamaYieldPoolsResponse,
} from './defi-llama-types';

const API_BASE = 'https://api.llama.fi';
const YIELDS_BASE = 'https://yields.llama.fi';

/** Cache entry with expiration. */
interface CacheEntry<T> {
  data: T;
  expiresAt: number;
}

/**
 * DefiLlama adapter for DeFi protocol TVL metrics and yield pool data.
 *
 * Provides normalized access to protocol TVL rankings, individual protocol
 * details, and yield pool APY data across all supported chains. Uses REST
 * polling with a 60-second cache to minimize redundant requests.
 *
 * Rate limited to 300 calls per 5 minutes per DefiLlama's public API limits.
 * No authentication required.
 */
export class DefiLlamaAdapter {
  readonly exchangeId = 'defi-llama' as const;
  readonly displayName = 'DefiLlama';
  readonly category: AdapterCategory = 'data-provider';
  readonly capabilities: AdapterCapabilities = {
    realtime: false,
    historicalDepth: '1y',
    orderbook: false,
    trades: false,
    ohlcv: false,
    fundingRates: false,
    openInterest: false,
    liquidations: false,
    defiMetrics: true,
    onChainMetrics: false,
    authenticated: false,
  };

  private connected = false;
  private pollingInterval: ReturnType<typeof setInterval> | undefined;
  private readonly rateLimiter: RateLimiter;
  private readonly cache = new Map<string, CacheEntry<unknown>>();

  private static readonly PROTOCOL_CACHE_TTL_MS = 60_000;
  private static readonly YIELD_CACHE_TTL_MS = 60_000;
  private static readonly POLL_INTERVAL_MS = 60_000;
  private static readonly TOP_PROTOCOLS_COUNT = 100;

  constructor() {
    this.rateLimiter = new RateLimiter('defi-llama', {
      maxTokens: 300,
      windowMs: 300_000,
      queueExcess: true,
      maxQueueDepth: 50,
    });
  }

  /** Start periodic background polling for protocol data. */
  async connect(): Promise<void> {
    if (this.connected) return;
    this.connected = true;
    this.pollingInterval = setInterval(() => {
      this.getProtocols().catch(() => {
        /* swallow background polling errors — stale cache is acceptable */
      });
    }, DefiLlamaAdapter.POLL_INTERVAL_MS);
  }

  /** Stop background polling and clear cached data. */
  async disconnect(): Promise<void> {
    if (!this.connected) return;
    this.connected = false;
    if (this.pollingInterval !== undefined) {
      clearInterval(this.pollingInterval);
      this.pollingInterval = undefined;
    }
    this.cache.clear();
    this.rateLimiter.dispose();
  }

  /** Whether the adapter is currently connected and polling. */
  isConnected(): boolean {
    return this.connected;
  }

  getHealthMetrics(): HealthMetrics {
    return {
      connected: this.connected,
      latencyMs: 0,
      messagesPerSecond: 0,
      uptimePercent: this.connected ? 100 : 0,
      lastMessageAt: 0,
      errorRate: 0,
      circuitBreakerState: 'closed',
    };
  }

  /**
   * Fetch top 100 protocols by TVL.
   *
   * Results are cached for 60 seconds. Protocols with null TVL are excluded
   * from the ranking.
   */
  async getProtocols(): Promise<NormalizedProtocolMetrics[]> {
    const cached = this.getCached<NormalizedProtocolMetrics[]>('protocols');
    if (cached !== undefined) return cached;

    const raw = await this.fetchJson<DefiLlamaRawProtocol[]>(`${API_BASE}/protocols`);

    const sorted = raw
      .filter((p): p is DefiLlamaRawProtocol & { tvl: number } => p.tvl !== null && p.tvl > 0)
      .sort((a, b) => b.tvl - a.tvl)
      .slice(0, DefiLlamaAdapter.TOP_PROTOCOLS_COUNT);

    const now = Date.now();
    const result = sorted.map((p) => this.normalizeProtocol(p, now));

    this.setCache('protocols', result, DefiLlamaAdapter.PROTOCOL_CACHE_TTL_MS);
    return result;
  }

  /**
   * Fetch detailed metrics for a single protocol.
   *
   * @param protocolId - Protocol slug (e.g., "aave", "uniswap").
   */
  async getProtocol(protocolId: string): Promise<NormalizedProtocolMetrics> {
    const cacheKey = `protocol:${protocolId}`;
    const cached = this.getCached<NormalizedProtocolMetrics>(cacheKey);
    if (cached !== undefined) return cached;

    const raw = await this.fetchJson<DefiLlamaRawProtocolDetail>(
      `${API_BASE}/protocol/${encodeURIComponent(protocolId)}`,
    );

    const lastTvlEntry = raw.tvl.length > 0 ? raw.tvl[raw.tvl.length - 1] : undefined;
    const currentTvl = lastTvlEntry?.totalLiquidityUSD ?? 0;
    const now = Date.now();

    const result: NormalizedProtocolMetrics = {
      protocolId: raw.slug,
      name: raw.name,
      chain: raw.chain,
      tvlUsd: currentTvl,
      tvlChange24h: raw.change_1d ?? 0,
      volume24h: 0,
      fees24h: 0,
      revenue24h: 0,
      timestamp: now,
    };

    this.setCache(cacheKey, result, DefiLlamaAdapter.PROTOCOL_CACHE_TTL_MS);
    return result;
  }

  /**
   * Fetch yield pool data.
   *
   * @param options.chain - Filter by chain name (e.g., "Ethereum", "Arbitrum").
   * @param options.limit - Maximum number of pools to return (default: 100).
   */
  async getYieldPools(options?: { chain?: string; limit?: number }): Promise<NormalizedYieldPool[]> {
    const chain = options?.chain;
    const limit = options?.limit ?? 100;
    const cacheKey = `yields:${chain ?? 'all'}:${limit}`;

    const cached = this.getCached<NormalizedYieldPool[]>(cacheKey);
    if (cached !== undefined) return cached;

    const response = await this.fetchJson<DefiLlamaYieldPoolsResponse>(`${YIELDS_BASE}/pools`);

    let pools = response.data;

    if (chain) {
      const chainLower = chain.toLowerCase();
      pools = pools.filter((p) => p.chain.toLowerCase() === chainLower);
    }

    const now = Date.now();
    const result = pools
      .filter((p) => p.tvlUsd > 0)
      .sort((a, b) => b.tvlUsd - a.tvlUsd)
      .slice(0, limit)
      .map((p) => this.normalizeYieldPool(p, now));

    this.setCache(cacheKey, result, DefiLlamaAdapter.YIELD_CACHE_TTL_MS);
    return result;
  }

  private normalizeProtocol(raw: DefiLlamaRawProtocol, timestamp: number): NormalizedProtocolMetrics {
    return {
      protocolId: raw.slug,
      name: raw.name,
      chain: raw.chain,
      tvlUsd: raw.tvl ?? 0,
      tvlChange24h: raw.change_1d ?? 0,
      volume24h: 0,
      fees24h: 0,
      revenue24h: 0,
      timestamp,
    };
  }

  private normalizeYieldPool(raw: DefiLlamaRawYieldPool, timestamp: number): NormalizedYieldPool {
    return {
      poolId: raw.pool,
      protocolId: raw.project,
      chain: raw.chain,
      symbol: raw.symbol,
      apy: raw.apy,
      tvlUsd: raw.tvlUsd,
      apyBase: raw.apyBase ?? 0,
      apyReward: raw.apyReward ?? 0,
      timestamp,
    };
  }

  private async fetchJson<T>(url: string): Promise<T> {
    await this.rateLimiter.acquire();

    const response = await fetch(url, {
      method: 'GET',
      headers: { Accept: 'application/json' },
    });

    if (!response.ok) {
      const body = await response.text().catch(() => '');
      throw new Error(
        `DefiLlama API error: ${response.status} ${response.statusText}${body ? ` — ${body}` : ''}`,
      );
    }

    return response.json() as Promise<T>;
  }

  private getCached<T>(key: string): T | undefined {
    const entry = this.cache.get(key) as CacheEntry<T> | undefined;
    if (!entry) return undefined;
    if (Date.now() >= entry.expiresAt) {
      this.cache.delete(key);
      return undefined;
    }
    return entry.data;
  }

  private setCache<T>(key: string, data: T, ttlMs: number): void {
    this.cache.set(key, { data, expiresAt: Date.now() + ttlMs });
  }
}
